import{c as o,Q as s,j as a,m as n}from"./chunks/framework.Bhbi9jCp.js";const p=JSON.parse('{"title":"红石:信号传播、更新顺序与图灵完备","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/14-红石-信号传播更新顺序与图灵完备.md","filePath":"minecraftLearning/14-红石-信号传播更新顺序与图灵完备.md","lastUpdated":1781676649000}'),r={name:"minecraftLearning/14-红石-信号传播更新顺序与图灵完备.md"};function e(i,t,l,c,u,d){return s(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="红石-信号传播、更新顺序与图灵完备" tabindex="-1">红石:信号传播、更新顺序与图灵完备 <a class="header-anchor" href="#红石-信号传播、更新顺序与图灵完备" aria-label="Permalink to &quot;红石:信号传播、更新顺序与图灵完备&quot;">​</a></h1><p>红石是 Minecraft 里最被低估的一块——表面上是&quot;会发光的红粉末&quot;,底层其实是一套<strong>沿方块传播的信号系统 + 一套确定性的更新调度</strong>。它能搭出加法器、寄存器,乃至完整的计算机,不是因为引擎里藏了什么&quot;红石虚拟机&quot;,而是因为前面讲过的那套<strong>邻居通知级联</strong>(第 04 篇)恰好满足了构建逻辑门的全部条件。</p><p>这一篇把红石从 tick 系统里单拎出来讲透:信号怎么传、为什么会有方向和延迟、为什么 Java 和 Bedrock 的红石电路互不通用、以及&quot;它凭什么图灵完备&quot;。</p><blockquote><p>一句话先记住:<strong>红石不是一种&quot;东西&quot;,而是 BlockState 上一个 0–15 的信号值 + 邻居更新级联 + scheduled tick 调度三者叠出来的现象。</strong> 红石技术的所有玄学(quasi-connectivity、0-tick、BUD)本质都是在钻&quot;更新顺序&quot;的空子。</p></blockquote><hr><h2 id="一、信号-0–15-的强度与每格衰减" tabindex="-1">一、信号:0–15 的强度与每格衰减 <a class="header-anchor" href="#一、信号-0–15-的强度与每格衰减" aria-label="Permalink to &quot;一、信号:0–15 的强度与每格衰减&quot;">​</a></h2><p>红石的核心量是一个 <strong>0–15 的信号强度(power level)</strong>,存在相关方块的 BlockState 里(红石线的 <code>power</code> 属性、中继器的 <code>powered</code> 等)。</p><ul><li><strong>源</strong>把强度拉到某个值:红石块/拉杆/按钮/压力板给 <strong>15</strong>,红石火把给 15,日光传感器、比较器按条件给 0–15。</li><li><strong>红石线(redstone wire)</strong> 传导时<strong>每格衰减 1</strong>:紧挨 15 的那格是 14,再下一格 13……到 0 就断了。所以一条裸线最远传 <strong>15 格</strong>,要更远必须用中继器&quot;续杯&quot;。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[源15] - 14 - 13 - 12 - ... - 1 - 0(断)</span></span>
<span class="line"><span>              红石线每格 -1</span></span></code></pre></div><p>这个&quot;每格 -1&quot;不是装饰,它是<strong>距离的物理表达</strong>:比较器能读出这个强度差,于是红石线本身就能当&quot;距离传感器&quot;用。</p><h3 id="两个不简单的元件" tabindex="-1">两个不简单的元件 <a class="header-anchor" href="#两个不简单的元件" aria-label="Permalink to &quot;两个不简单的元件&quot;">​</a></h3><ul><li><strong>中继器(repeater)</strong>:四个作用揉在一起——<strong>单向导通</strong>(只朝一个方向)、<strong>把信号重新拉回 15</strong>(放大/续传)、<strong>可调延迟</strong>(1–4 个红石刻,见下)、<strong>锁存</strong>(被侧向信号锁住时保持当前输出)。它是把&quot;线&quot;变成&quot;有向、有时序的电路&quot;的关键。</li><li><strong>比较器(comparator)</strong>:两种模式。<strong>比较模式</strong>——主输入 ≥ 侧输入才放行;<strong>减法模式</strong>——输出 = 主输入 − 侧输入。更重要的是它能<strong>读容器满度</strong>:对着箱子/熔炉/唱片机放,输出强度正比于容器填充比例。这让红石能&quot;感知世界状态&quot;,而不只是开关。</li></ul><hr><h2 id="二、底层-一切都是邻居更新级联" tabindex="-1">二、底层:一切都是邻居更新级联 <a class="header-anchor" href="#二、底层-一切都是邻居更新级联" aria-label="Permalink to &quot;二、底层:一切都是邻居更新级联&quot;">​</a></h2><p>红石看着像&quot;电流在流动&quot;,但引擎里<strong>没有电流</strong>,只有<strong>方块更新的级联传播</strong>——就是第 04 篇讲的 <code>neighborChanged</code>。</p><p>某个方块的供能状态变了 → 它<strong>立即通知周围方块</strong>重算 → 邻居发现自己的输入变了、状态也变 → 再通知它的邻居……一圈圈传出去,<strong>在同一 tick 内</strong>完成大部分传播。红石线的&quot;亮起来&quot;就是这条级联扫过的结果。</p><h3 id="硬供能-vs-弱供能-必须分清" tabindex="-1">硬供能 vs 弱供能(必须分清) <a class="header-anchor" href="#硬供能-vs-弱供能-必须分清" aria-label="Permalink to &quot;硬供能 vs 弱供能(必须分清)&quot;">​</a></h3><p>这是新手最容易栽的地方:</p><table tabindex="0"><thead><tr><th></th><th>硬供能(strong)</th><th>弱供能(weak)</th></tr></thead><tbody><tr><td>谁产生</td><td>中继器/比较器正前方的实心方块、红石块本身</td><td>红石线压在实心方块上</td></tr><tr><td>能否再点亮相邻红石线</td><td>能</td><td><strong>不能</strong></td></tr><tr><td>直观表现</td><td>被硬供能的石头,它周围的红石线会亮</td><td>被弱供能的石头,周围红石线<strong>不亮</strong></td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>中继器 → [石头] → 红石线亮      (石头被硬供能,可二次驱动红石)</span></span>
<span class="line"><span>红石线 → [石头] → 红石线不亮    (石头只被弱供能,不能二次驱动红石)</span></span></code></pre></div><p>&quot;被供能的方块能不能继续点亮别的红石&quot;——这个区别决定了无数电路能不能work,却完全不在表面可见。理解红石电路出 bug,八成是硬/弱供能搞混了。</p><hr><h2 id="三、时序-红石刻与-scheduled-tick" tabindex="-1">三、时序:红石刻与 scheduled tick <a class="header-anchor" href="#三、时序-红石刻与-scheduled-tick" aria-label="Permalink to &quot;三、时序:红石刻与 scheduled tick&quot;">​</a></h2><p>红石的&quot;延迟&quot;不是动画,是<strong>真实的 scheduled tick 调度</strong>(第 04 篇那套计划刻队列)。</p><ul><li>计量单位是<strong>红石刻(redstone tick)= 2 个游戏 tick = 0.1 秒</strong>。中继器默认延迟 1 红石刻,可调到 4(0.4 秒)。</li><li>中继器/活塞/红石火把改变状态时,不是立刻翻转,而是<strong>给自己排一个 scheduled tick</strong>,到期才翻。这就是延迟的来源,也是为什么红石电路有确定的时序而非瞬间雪崩。</li><li>红石火把还有<strong>烧毁(burnout)机制</strong>:在很短时间内被反复强制翻转会暂时熄灭,这是防止零延迟自激振荡的硬限制。</li></ul><p>时序之所以<strong>确定</strong>,靠的是 scheduled tick 的<strong>优先级(TickPriority,-3~+3)</strong> 给同一 tick 内到期的任务排了序——否则&quot;谁先翻&quot;就成了随机,电路无法复现。</p><hr><h2 id="四、玄学的来源-钻-更新顺序-的空子" tabindex="-1">四、玄学的来源:钻&quot;更新顺序&quot;的空子 <a class="header-anchor" href="#四、玄学的来源-钻-更新顺序-的空子" aria-label="Permalink to &quot;四、玄学的来源:钻&quot;更新顺序&quot;的空子&quot;">​</a></h2><p>红石技术里那些听起来像作弊的东西,全是利用了&quot;更新是有顺序、有时间窗口&quot;这一事实。</p><h3 id="quasi-connectivity-准连接-——-java-bedrock-分裂的根源" tabindex="-1">quasi-connectivity(准连接)—— Java/Bedrock 分裂的根源 <a class="header-anchor" href="#quasi-connectivity-准连接-——-java-bedrock-分裂的根源" aria-label="Permalink to &quot;quasi-connectivity(准连接)—— Java/Bedrock 分裂的根源&quot;">​</a></h3><p><strong>活塞、漏斗、投掷器这些机械方块,判断自己是否被供能时,除了检查自身,还会额外检查&quot;正上方那一格&quot;是否被供能。</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   [被供能的方块]   ← 活塞会把这里的供能也算到自己头上</span></span>
<span class="line"><span>   [ 活 塞 ]        ← 于是活塞伸出,哪怕它自己那格没被直接供能</span></span></code></pre></div><p>这是远古遗留的&quot;特性 bug&quot;。它让大量经典电路(瞬时门、某些飞行器、BUD)成立。<strong>Java 版保留了它,Bedrock 版重写时去掉了</strong>——这正是<strong>两版红石电路互不通用</strong>的最大单一原因。很多 Java 教程搬到 Bedrock 直接不work,根子就在这。</p><h3 id="_0-tick、bud、observer" tabindex="-1">0-tick、BUD、observer <a class="header-anchor" href="#_0-tick、bud、observer" aria-label="Permalink to &quot;0-tick、BUD、observer&quot;">​</a></h3><ul><li><strong>0-tick</strong>:利用&quot;同一 tick 内,scheduled tick 还没结算&quot;的窗口,在一个 tick 里对活塞/作物做多次触发。本质是抢在调度队列处理之前插队。后续版本部分被官方修掉。</li><li><strong>BUD(Block Update Detector)</strong>:在 quasi-connectivity 出现之前,人们用活塞&quot;被相邻方块更新意外触发&quot;来探测远处变化——它探测的就是<strong>邻居通知</strong>本身。</li><li><strong>observer(观察者)</strong>:官方后来给的&quot;正规 BUD&quot;——它监听正前方方块的 BlockState 变化,变了就输出一个脉冲。等于把&quot;我想知道某方块更新了&quot;这个需求<strong>做成了一等公民</strong>,不必再靠 quasi 的副作用。</li></ul><p>把这三个放一起看:<strong>红石高玩玩的不是电路,是 Minecraft 的更新调度器。</strong></p><hr><h2 id="五、为什么红石图灵完备" tabindex="-1">五、为什么红石图灵完备 <a class="header-anchor" href="#五、为什么红石图灵完备" aria-label="Permalink to &quot;五、为什么红石图灵完备&quot;">​</a></h2><p>构建一台计算机只需要三样东西:<strong>与/或/非逻辑、能存状态、能按时钟推进</strong>。红石全有:</p><ol><li><strong>逻辑门</strong>:红石火把本身就是一个<strong>非门(NOT)</strong>——它给所在方块供能,但被供能时自己熄灭。有了 NOT + 信号合并(OR)+ 串联条件,就能搭出 AND/NAND/XOR 全套。</li><li><strong>存储</strong>:RS 锁存器、T 触发器用中继器的锁存特性或火把回路实现,能<strong>保住一个 bit</strong>。拼起来就是寄存器、RAM。</li><li><strong>时钟</strong>:火把振荡器、中继器环路提供<strong>周期性脉冲</strong>,作为 CPU 的节拍。</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NOT(红石火把) + OR(信号汇合) + 锁存(中继器/触发器) + 时钟(振荡环)</span></span>
<span class="line"><span>   → 全套逻辑门 → 加法器 / ALU → 寄存器 → 取指执行 → 红石计算机</span></span></code></pre></div><p>于是社区里真的有人用红石搭出了带流水线的 CPU、跑得动简化版游戏。它不快(时钟以红石刻计,慢得令人发指),但<strong>计算能力上等价于一台通用计算机</strong>。而这套能力,完全是从&quot;邻居更新会级联、scheduled tick 有确定时序&quot;这两条引擎规则里<strong>涌现</strong>出来的,引擎从没专门为&quot;计算&quot;写过一行代码。</p><hr><h2 id="踩坑与反直觉" tabindex="-1">踩坑与反直觉 <a class="header-anchor" href="#踩坑与反直觉" aria-label="Permalink to &quot;踩坑与反直觉&quot;">​</a></h2><ul><li><strong>红石里没有&quot;电流&quot;</strong>,只有方块更新级联。别用电路直觉去想&quot;电子在跑&quot;,要想&quot;哪个方块的状态变了、它会通知谁&quot;。</li><li><strong>硬供能/弱供能不可见</strong>,是排查电路失灵的头号坑:红石线压着的石头不能再点亮相邻红石线,中继器顶着的石头可以。</li><li><strong>延迟是 scheduled tick,不是动画</strong>;时序确定性来自 TickPriority,而不是&quot;运气&quot;。</li><li><strong>quasi-connectivity 是 Java 专属</strong>:照搬到 Bedrock 必废。判断一个电路能不能跨版本,先问它依不依赖&quot;活塞看头顶&quot;。</li><li><strong>0-tick 这类是钻更新窗口</strong>,会随版本被修;依赖它的机器升级后可能突然坏掉。</li></ul><hr><h2 id="串联" tabindex="-1">串联 <a class="header-anchor" href="#串联" aria-label="Permalink to &quot;串联&quot;">​</a></h2><p>红石把第 04 篇那套抽象的&quot;邻居通知级联 + scheduled tick 调度&quot;变成了<strong>看得见、能搭出计算机</strong>的具体系统:信号是 BlendState 上的 0–15,传播靠邻居更新,时序靠计划刻,玄学靠钻更新顺序。它也第一次让&quot;Java 和 Bedrock 是两套实现&quot;变得切肤可感——quasi-connectivity 的有无,直接决定了一套电路能不能用。下一篇看<strong>刷怪机制</strong>,会发现它和红石一样,都死死绑在第 05 篇的 ticking 范围上:不在模拟距离内,红石不跑、怪也不刷。</p>`,48)])])}const h=o(r,[["render",e]]);export{p as __pageData,h as default};
